; ---------------------------------------------------------------------------
; External contracts used by this module
; - Far-call text entry wrapper: caller-local $20/$22 supplies the EF/text
;   pointer, which is restaged into the generic C1:86B1 pointer ABI.
; - C0:943C/C0:9451 bracket the text run with saved coordinate/state, while
;   $B4A8 == FFFF is the completion sentinel drained by C1:2DD5.
; - The tiny following entries are state latches for blinking prompt state and
;   text sound/display mode.

C0943C_SaveCurrentCoordinateState  = $C0943C
C09451_RestoreSavedCoordinateState = $C09451
C186B1_PrintTextFromPointer        = $C186B1
C12DD5_TickWindowTextSystem        = $C12DD5
CallerFrameTextPointerLo           = $20
CallerFrameTextPointerBank         = $22
LocalTextPointerLo                 = $06
LocalTextPointerBank               = $08
TextPointerLo                      = $0E
TextPointerBank                    = $10
ActiveTextCompletionState          = $B4A8
TextCompleteSentinel               = $FFFF
BlinkingTriangleState              = $964D
TextSoundMode                      = $964F

; ---------------------------------------------------------------------------
; C1:0004

C10004_ProcessTextboxDataFromCallerPointer:
    rep #$31
    phd
    tdc
    adc.w #$FFEE
    tcd
    lda CallerFrameTextPointerLo
    sta LocalTextPointerLo
    lda CallerFrameTextPointerBank
    sta LocalTextPointerBank
    jsl C0943C_SaveCurrentCoordinateState
    lda LocalTextPointerLo
    sta TextPointerLo
    lda LocalTextPointerBank
    sta TextPointerBank
    jsl C186B1_PrintTextFromPointer
C10024_ProcessTextboxDataFromCallerPointer_L0024:
    jsl C12DD5_TickWindowTextSystem
    lda ActiveTextCompletionState
    cmp.w #TextCompleteSentinel
    bne C10024_ProcessTextboxDataFromCallerPointer_L0024
    jsl C09451_RestoreSavedCoordinateState
    pld
    rtl
ENABLE_BLINKING_TRIANGLE:
C10036_SetBlinkingTriangleState = ENABLE_BLINKING_TRIANGLE
    rep #$31
    sta BlinkingTriangleState
    rts
CLEAR_BLINKING_PROMPT:
C1003C_ClearBlinkingTriangleState = CLEAR_BLINKING_PROMPT
    rep #$31
